/**
 * 用户管理模块 - 提供用户相关的CRUD操作
 * @module services/userService
 */

/**
 * 创建新用户
 * @async
 * @function createUser
 * @param {Object} userData - 用户数据对象
 * @param {string} userData.username - 用户名（3-20个字符）
 * @param {string} userData.email - 电子邮箱地址
 * @param {string} userData.password - 密码（至少8位，包含大小写字母和数字）
 * @param {string} [userData.avatar] - 头像URL（可选）
 * @returns {Promise<Object>} 返回创建的用户对象，包含id、username、email、createdAt
 * @throws {ValidationError} 当输入数据验证失败时抛出
 * @throws {DuplicateError} 当用户名或邮箱已存在时抛出
 * @example
 * const user = await createUser({
 *   username: 'john_doe',
 *   email: 'john@example.com',
 *   password: 'SecurePass123'
 * });
 */
async function createUser(userData) {
  // 验证输入
  if (!validateInput(userData)) {
    throw new ValidationError('Invalid user data');
  }

  // 检查重复
  const existing = await findByEmail(userData.email);
  if (existing) {
    throw new DuplicateError('User already exists');
  }

  // 创建用户
  const hashedPassword = await bcrypt.hash(userData.password, 10);
  return await UserModel.create({
    username: userData.username,
    email: userData.email,
    password: hashedPassword,
    avatar: userData.avatar || 'default.png'
  });
}


### 示例 2：Python DocString 文档生成

python
"""
数据处理模块 - 提供数据清洗、转换和分析功能
"""

from typing import List, Dict, Optional, Union
from dataclasses import dataclass


@dataclass
class ProcessingResult:
    """处理结果数据类"""
    success: bool
    data: List[Dict]
    errors: List[str]
    processed_count: int


def clean_and_transform_data(
    raw_data: List[Dict],
    schema: Dict[str, str],
    remove_nulls: bool = True,
    normalize: bool = False
) -> ProcessingResult:
    """
    清洗和转换原始数据。

    根据提供的 schema 定义对原始数据进行类型转换、
    字段映射、空值处理和规范化操作。

    Args:
        raw_data: 原始数据列表，每个元素是一个字典
        schema: 数据模式定义，key为原始字段名，value为目标类型
                 例如: {"user_id": "int", "name": "str", "score": "float"}
        remove_nulls: 是否移除包含空值的记录，默认为 True
        normalize: 是否对数值字段进行 Min-Max 归一化，默认为 False

    Returns:
        ProcessingResult: 包含处理状态、数据、错误信息和统计计数的结果对象

    Raises:
        ValueError: 当 schema 为空或格式不正确时抛出
        TypeError: 当数据类型无法转换时抛出

    Example:
        >>> data = [{"user_id": "1", "name": "Alice", "score": "85.5"}]
        >>> schema = {"user_id": "int", "name": "str", "score": "float"}
        >>> result = clean_and_transform_data(data, schema)
        >>> print(f"Processed {result.processed_count} records")
    """
    if not schema:
        raise ValueError("Schema cannot be empty")

    cleaned_data = []
    errors = []

    for index, record in enumerate(raw_data):
        try:
            transformed_record = {}
            for field, target_type in schema.items():
                value = record.get(field)

                # 处理空值
                if value is None or value == "":
                    if remove_nulls:
                        errors.append(f"Row {index}: Null value in field '{field}'")
                        break
                    else:
                        transformed_record[field] = None
                        continue

                # 类型转换
                transformed_record[field] = convert_type(value, target_type)

            if field not in errors or not remove_nulls:
                cleaned_data.append(transformed_record)

        except Exception as e:
            errors.append(f"Row {index}: {str(e)}")

    return ProcessingResult(
        success=len(errors) == 0,
        data=cleaned_data,
        errors=errors,
        processed_count=len(cleaned_data)
    )


def convert_type(value: str, target_type: str) -> Union[int, float, str]:
    """辅助函数：进行类型转换"""
    converters = {
        "int": lambda x: int(float(x)),
        "float": lambda x: float(x),
        "str": lambda x: str(x)
    }
    return converters.get(target_type, str)(value)


