const vscode = require('vscode');

/**
 * 自定义内联补全提供者
 * 当用户输入特定触发词时，提供预定义的代码片段
 */
function activate(context) {
    // 注册内联补全提供者
    const inlineCompletionProvider = vscode.languages.registerInlineCompletionItemProvider(
        { pattern: '**/*.js' }, // 只在 JavaScript 文件中生效
        {
            /**
             * 提供内联补全
             * @param {vscode.TextDocument} document - 当前文档对象
             * @param {vscode.Position} position - 光标位置
             * @param {vscode.InlineCompletionContext} context - 补全上下文
             * @param {vscode.CancellationToken} token - 取消令牌
             */
            provideInlineCompletionItems(document, position, context, token) {
                // 获取当前行的文本
                const line = document.lineAt(position);
                const lineText = line.text.substring(0, position.character);

                // 定义触发词和对应的补全内容
                const completions = {
                    '//todo': {
                        insertText: ' TODO: ',
                        detail: '添加待办事项标记',
                        documentation: '这是一个待办事项占位符，请在此处描述需要完成的任务'
                    },
                    '//fixme': {
                        insertText: ' FIXME: ',
                        detail: '添加需要修复的标记',
                        documentation: '这是一个需要修复的问题占位符'
                    },
                    'console.log(': {
                        insertText: 'console.log('),
                        detail: '控制台输出',
                        documentation: '在控制台输出调试信息'
                    }
                };

                // 遍历触发词，检查是否匹配
                for (const [trigger, completion] of Object.entries(completions)) {
                    if (lineText.endsWith(trigger)) {
                        // 返回内联补全项
                        return [new vscode.InlineCompletionItem(
                            completion.insertText,  // 要插入的文本
                            new vscode.Range(       // 替换范围
                                position,
                                position
                            ),
                            {
                                title: completion.detail,
                                documentation: completion.documentation
                            }
                        )];
                    }
                }

                // 如果没有匹配，返回空数组
                return [];
            }
        }
    );

    // 注册命令示例
    const commandDisposable = vscode.commands.registerCommand('extension.smartComment', () => {
        // 获取当前选中的文本
        const editor = vscode.window.activeTextEditor;
        if (!editor) {
            return;
        }

        const selection = editor.selection;
        const selectedText = editor.document.getText(selection);

        // 创建一个带时间戳的注释
        const date = new Date().toISOString().split('T')[0];
        const comment = `// [${date}] ${selectedText}`;

        // 替换选中文本
        editor.edit(editBuilder => {
            editBuilder.replace(selection, comment);
        });
    });

    // 将订阅添加到上下文中
    context.subscriptions.push(inlineCompletionProvider, commandDisposable);
}

// 插件停用时清理资源
function deactivate() {
    console.log('AI补全插件已停用');
}

module.exports = {
    activate,
    deactivate
};

// 示例2：使用 GitHub Copilot API 进行代码补全的简单演示
// 注意：这是一个概念性示例，实际使用需要官方授权

// 模拟一个简化的代码补全流程
class SimpleCodeCompleter {
    constructor(model = 'gpt-4') {
        this.model = model;
        this.context = [];
    }

    /**
     * 添加代码上下文
     * @param {string} code - 要添加的代码
     * @param {string} language - 编程语言
     */
    addContext(code, language = 'javascript') {
        this.context.push({
            role: 'user',
            content: code,
            metadata: { language }
        });
    }

    /**
     * 模拟生成代码补全
     * 实际应用中，这里会调用真实的 LLM API
     */
    async complete(prefix, maxTokens = 50) {
        // 构建提示词
        const prompt = this.buildPrompt(prefix);

        // 模拟 LLM 调用
        const completion = this.simulateLLM(prompt, maxTokens);

        return completion;
    }

    /**
     * 构建提示词
     * 这是提示词工程的核心，决定了 AI 的输出质量
     */
    buildPrompt(prefix) {
        // 系统提示词：定义 AI 的角色和能力边界
        const systemPrompt = `你是一个专业的代码助手。
请根据上下文和用户输入，生成最合适的代码补全。

规则：
1. 只输出代码，不要解释
2. 保持代码风格一致
3. 遵循最佳实践
4. 如果输入不完整，尝试补全
5. 如果有多种可能，提供最常用的那种`;

        // 组合上下文
        const contextText = this.context
            .map(ctx => `[${ctx.metadata.language}]\n${ctx.content}`)
            .join('\n\n');

        return `${systemPrompt}\n\n上下文：\n${contextText}\n\n当前输入：\n${prefix}\n\n补全：`;
    }

    /**
     * 模拟 LLM 响应
     * 实际应用中，这里需要调用真实的 API
     */
    simulateLLM(prompt, maxTokens) {
        // 模拟常见的补全场景
        const completions = {
            'function ': 'hello() {\n    console.log("Hello, World!");\n}',
            'if (': 'isValid) {\n    return true;\n} else {\n    return false;\n}',
            'for (': 'let i = 0; i < arr.length; i++) {\n    // 处理每个元素\n}',
            'const ': 'data = await fetchData();\nconsole.log(data);',
            'import ': 'React from "react";\nimport { useState } from "react";'
        };

        // 根据前缀匹配补全
        for (const [trigger, completion] of Object.entries(completions)) {
            if (prompt.includes(trigger)) {
                return {
                    text: completion,
                    trigger: trigger,
                    confidence: 0.95,
                    model: this.model
                };
            }
        }

        return {
            text: '// 继续输入代码以获得补全建议',
            confidence: 0.0,
            model: this.model
        };
    }

    /**
     * 清除上下文
     */
    clearContext() {
        this.context = [];
    }
}

// 使用示例
async function demo() {
    const completer = new SimpleCodeCompleter('gpt-4');

    // 添加一些上下文
    completer.addContext(`
// 工具函数
function formatDate(date) {
    return date.toISOString().split('T')[0];
}

function capitalize(str) {
    return str.charAt(0).toUpperCase() + str.slice(1);
}
`, 'javascript');

    // 获取补全
    const completion1 = await completer.complete('function ');
    console.log('补全1:', completion1.text);

    const completion2 = await completer.complete('if (');
    console.log('补全2:', completion2.text);
}

// 运行演示
demo();

// 实际使用建议：
// 1. 使用官方 API（需要申请 API key）
// 2. 考虑使用开源的本地模型（如 CodeLlama、StarCoder）
// 3. 实施速率限制和缓存策略
// 4. 监控使用成本和质量

// 示例3：创建一个分析代码上下文的工具
// 这个工具展示了如何收集和利用代码上下文信息

const vscode = require('vscode');

/**
 * 代码上下文分析器
 * 收集对 AI 补全有用的上下文信息
 */
class CodeContextAnalyzer {
    constructor() {
        this.maxLines = 100; // 最大收集行数
    }

    /**
     * 收集当前光标位置的上下文
     * @param {vscode.TextEditor} editor - 当前编辑器
     * @param {vscode.Position} position - 光标位置
     * @returns {Object} 上下文信息
     */
    collectContext(editor, position) {
        const document = editor.document;
        const fullText = document.getText();
        const fileName = document.fileName;
        const languageId = document.languageId;

        // 获取当前函数/方法
        const currentFunction = this.findCurrentFunction(document, position);

        // 获取最近打开的文件
        const recentFiles = this.getRecentFiles();

        // 获取导入语句
        const imports = this.extractImports(document);

        // 获取相关符号
        const relatedSymbols = this.findRelatedSymbols(document, position);

        return {
            file: {
                name: fileName,
                language: languageId,
                totalLines: document.lineCount
            },
            cursor: {
                line: position.line + 1,
                column: position.character + 1
            },
            currentFunction,
            imports,
            recentFiles,
            relatedSymbols,
            surroundingCode: this.getSurroundingCode(document, position)
        };
    }

    /**
     * 查找当前光标所在的函数/方法
     */
    findCurrentFunction(document, position) {
        const text = document.getText();
        const lines = text.split('\n');

        // 简单的函数检测正则（实际应用中需要更复杂的解析）
        const functionPattern = /(?:function\s+(\w+)|(\w+)\s*\(|class\s+(\w+))/g;

        let currentFunction = null;
        let lastMatch = null;

        for (let i = 0; i <= position.line; i++) {
            const match = functionPattern.exec(lines[i]);
            if (match && match.index <= position.character) {
                currentFunction = {
                    name: match[1] || match[2] || match[3],
                    line: i + 1,
                    type: match[3] ? 'class' : 'function'
                };
            }
        }

        return currentFunction;
    }

    /**
     * 提取导入语句
     */
    extractImports(document) {
        const text = document.getText();
        const importPattern = /(?:import|require|using|from)\s+[^;'"\n]+/g;
        const matches = text.match(importPattern) || [];

        return matches.map(imp => imp.trim()).slice(0, 20); // 最多20个
    }

    /**
     * 获取最近打开的文件
     */
    getRecentFiles() {
        // 获取工作区中的所有文件
        const workspaceFolders = vscode.workspace.workspaceFolders;
        if (!workspaceFolders) return [];

        const files = [];

        // 遍历工作区文件夹
        workspaceFolders.forEach(folder => {
            const pattern = new vscode.RelativePattern(folder, '**/*.{js,ts,py,java,go,rs}');
            vscode.workspace.findFiles(pattern, null, 10).then(uris => {
                files.push(...uris.map(u => u.fsPath));
            });
        });

        return files.slice(0, 5);
    }

    /**
     * 查找相关的符号（变量、函数等）
     */
    findRelatedSymbols(document, position) {
        // 使用 VS Code 的语言服务获取符号
        return vscode.commands.executeCommand(
            'vscode.executeDocumentSymbolProvider',
            document.uri
        ).then(symbols => {
            if (!symbols) return [];

            // 简化处理，只返回函数和类
            return symbols.filter(s =>
                s.kind === vscode.SymbolKind.Function ||
                s.kind === vscode.SymbolKind.Class
            );
        });
    }

    /**
     * 获取光标周围的代码
     */
    getSurroundingCode(document, position) {
        const startLine = Math.max(0, position.line - 20);
        const endLine = Math.min(document.lineCount - 1, position.line + 20);

        const lines = [];
        for (let i = startLine; i <= endLine; i++) {
            const line = document.lineAt(i);
            lines.push({
                lineNumber: i + 1,
                text: line.text,
                isCurrentLine: i === position.line
            });
        }

        return lines;
    }

    /**
     * 生成用于 AI 的提示上下文
     */
    generatePromptContext(context) {
        let prompt = `文件: ${context.file.name} (${context.file.language})\n`;
        prompt += `当前行: ${context.cursor.line}, ${context.cursor.column}\n`;

        if (context.currentFunction) {
            prompt += `当前位置: ${context.currentFunction.type} ${context.currentFunction.name}\n`;
        }

        prompt += '\n导入语句:\n';
        context.imports.forEach(imp => {
            prompt += `  ${imp}\n`;
        });

        prompt += '\n周围代码:\n';
        context.surroundingCode.forEach(line => {
            const marker = line.isCurrentLine ? '>>> ' : '    ';
            prompt += `${marker}${line.lineNumber}: ${line.text}\n`;
        });

        return prompt;
    }
}

// 使用示例
function showContextInfo() {
    const editor = vscode.window.activeTextEditor;
    if (!editor) {
        vscode.window.showInformationMessage('请打开一个文件');
        return;
    }

    const analyzer = new CodeContextAnalyzer();
    const context = analyzer.collectContext(editor, editor.selection.active);
    const promptContext = analyzer.generatePromptContext(context);

    console.log('=== 代码上下文信息 ===');
    console.log(promptContext);
}

module.exports = CodeContextAnalyzer;

