    "tests/*.ts": "测试代码"

// 使用示例：在 PR 中触发 CodeRabbit 审查
// 1. 安装 CodeRabbit VS Code 插件
// 2. 提交代码并创建 PR
// 3. CodeRabbit 自动分析变更并生成审查报告

// 示例：创建一个需要审查的功能模块
// src/services/OrderService.ts

class OrderService {
    async createOrder(orderData) {
        // 🔴 CodeRabbit 会检查：
        // 1. 参数验证是否完整
        // 2. 事务处理是否正确
        // 3. 错误处理是否完善

        if (!orderData.items || orderData.items.length === 0) {
            throw new Error('订单至少需要一个商品');
        }

        // 🟠 CodeRabbit 会建议：
        // - 添加价格计算的边界检查
        // - 考虑使用事务确保数据一致性
        const totalAmount = orderData.items.reduce(
            (sum, item) => sum + item.price * item.quantity, 
            0
        );

        // ✅ 完整实现应包含：
        // - 参数验证
        // - 事务处理
        // - 错误重试
        // - 日志记录
        // - 事件发布

        const order = {
            id: this.generateOrderId(),
            items: orderData.items,
            totalAmount,
            createdAt: new Date()
        };

        return order;
    }

    private generateOrderId() {
        return `ORD-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    }
}

export default OrderService;
```



## 常见错误

- 完全依赖 AI 审查结果，忽略人工复核
- 对所有警告都进行修复，未区分误报和真实问题
- 忽视 AI 的上下文限制，对超长文件进行一次性分析
- 未配置合适的审查规则，导致大量无关警告
- 将 AI 审查结果直接用于生产代码，未验证可运行性
- 认为 AI 能理解所有业务逻辑，对不合理建议盲目采纳
- 忽略 AI 工具的更新和新功能，未持续优化使用体验


## 最佳实践

- 建立 AI 审查与人工复核的协同机制，明确各自的职责范围
- 根据项目特点定制审查规则，过滤无关的警告类型
- 对关键安全问题进行交叉验证，确保 AI 判断准确
- 保持对代码意图和业务逻辑的理解，作为复核的基础
- 定期回顾 AI 审查结果，识别常见误报模式并调整配置
- 将 AI 审查集成到 CI/CD 流程，确保代码合并前通过质量检查
- 关注团队成员的反馈，持续优化工具配置和使用习惯
- 在重要决策上保持人类主导，AI 仅作为辅助建议来源

