### 3.3 示例三：行为一致性验证

#### 重构前后的对比测试

javascript
// ============ 测试框架设置（使用 Jest）============

// 待测试的计算模块
const calculationModule = require('./calculations');

describe('重构前后行为一致性测试', () => {

  // 测试用例：相同输入应该产生相同输出
  const testCases = [
    {
      name: '基础加法',
      input: { a: 2, b: 3 },
      expected: 5
    },
    {
      name: '负数运算',
      input: { a: -5, b: 10 },
      expected: 5
    },
    {
      name: '浮点数运算',
      input: { a: 0.1, b: 0.2 },
      expected: 0.3,
      precision: 10 // 浮点数精度容差
    },
    {
      name: '大数运算',
      input: { a: 999999999, b: 1 },
      expected: 1000000000
    },
    {
      name: '边界情况：零',
      input: { a: 0, b: 0 },
      expected: 0
    }
  ];

  testCases.forEach(({ name, input, expected, precision }) => {
    test(`加法计算 - ${name}`, () => {
      const result = calculationModule.add(input.a, input.b);

      if (precision) {
        // 浮点数使用近似比较
        expect(result).toBeCloseTo(expected, precision);
      } else {
        expect(result).toBe(expected);
      }
    });
  });

  // ============ 回归测试：API 兼容性验证 ============
  describe('API 兼容性回归测试', () => {

    test('函数签名保持一致', () => {
      // 验证函数存在
      expect(typeof calculationModule.add).toBe('function');

      // 验证参数数量
      expect(calculationModule.add.length).toBe(2);

      // 验证返回值类型
      const result = calculationModule.add(1, 2);
      expect(typeof result).toBe('number');
    });

    test('错误处理行为一致', () => {
      // 非数字输入应抛出错误
      expect(() => calculationModule.add('a', 1)).toThrow();
      expect(() => calculationModule.add(1, null)).toThrow();
      expect(() => calculationModule.add(undefined, 1)).toThrow();
    });

    test('特殊值处理一致', () => {
      // NaN 传播
      expect(Number.isNaN(calculationModule.add(NaN, 1))).toBe(true);

      // Infinity 处理
      expect(calculationModule.add(Infinity, 1)).toBe(Infinity);
      expect(calculationModule.add(-Infinity, 1)).toBe(-Infinity);
    });
  });

  // ============ 快照测试：复杂对象对比 ============
  describe('复杂对象处理一致性', () => {

    test('订单总额计算保持一致', () => {
      const orderInput = {
        items: [
          { price: 10.99, quantity: 2 },
          { price: 5.50, quantity: 1 },
          { price: 2.00, quantity: 3 }
        ],
        discount: 5
      };

      const result = calculationModule.calculateOrderTotal(orderInput);

      // 预期结果：(10.99 * 2) + (5.50 * 1) + (2.00 * 3) - 5 = 21.98 + 5.50 + 6 - 5 = 28.48
      expect(result).toBeCloseTo(28.48, 2);
    });

    test('空数组处理一致', () => {
      const emptyOrder = { items: [], discount: 0 };
      expect(calculationModule.calculateOrderTotal(emptyOrder)).toBe(0);
    });

    test('负折扣处理一致（实际是加价）', () => {
      const order = {
        items: [{ price: 100, quantity: 1 }],
        discount: -10 // 负折扣 = 加价
      };
      expect(calculationModule.calculateOrderTotal(order)).toBe(110);
    });
  });
});

