// React Hooks 与类型示例
import { useState, useEffect } from 'react';

// AI 会推断返回值的类型并提供适当的 hooks 建议
function useUserData(userId: string) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    async function fetchUser() {
      try {
        setLoading(true);
        const response = await fetch(`/api/users/${userId}`);
        const data = await response.json();
        setUser(data);
      } catch (err) {
        setError(err as Error);
      } finally {
        setLoading(false);
      }
    }

    fetchUser();
  }, [userId]);

  // AI 会识别这是典型的异步数据获取模式
  // 并提供使用指南的建议
  return { user, loading, error };
}

# Python 数据科学栈示例
# 这展示了 AI 如何帮助你处理 pandas 和 numpy 操作

import pandas as pd
import numpy as np
from typing import Optional

# 定义数据处理管道
class DataProcessor:
    """数据处理器 - AI 会理解其方法和返回类型"""

    def __init__(self, df: pd.DataFrame):
        self.df = df

    def clean(self, columns: list[str]) -> pd.DataFrame:
        """清洗指定列的数据"""
        result = self.df.copy()
        for col in columns:
            # AI 会理解列的类型并提供适当的清洗方法
            if pd.api.types.is_numeric_dtype(result[col]):
                result[col] = result[col].fillna(result[col].median())
            else:
                result[col] = result[col].fillna('unknown')
        return result

    def aggregate(
        self,
        group_by: str,
        agg_funcs: dict[str, str]
    ) -> pd.DataFrame:
        """聚合操作 - AI 提供 agg_funcs 的建议"""
        return self.df.groupby(group_by).agg(agg_funcs)

# 类型化的 pandas Series 处理
def calculate_metrics(series: pd.Series[float]) -> dict[str, float]:
    """计算统计指标 - AI 理解数值序列的类型"""
    return {
        'mean': series.mean(),
        'std': series.std(),
        'median': series.median(),
        'q25': series.quantile(0.25),
        'q75': series.quantile(0.75),
    }

# 向量化操作示例
def vectorized_operation(data: np.ndarray) -> np.ndarray:
    """高效的向量化计算 - AI 推荐 numpy 的最佳实践"""
    # AI 会建议使用向量化操作而非循环
    normalized = (data - data.mean()) / data.std()
    return np.clip(normalized, -3, 3)

# 使用 pandas 的链式调用
def analyze_sales(df: pd.DataFrame) -> pd.DataFrame:
    """销售数据分析管道"""
    return (
        df
        .query('amount > 0')  # AI 提供 query 语法建议
        .assign(day_of_week=lambda x: x['date'].dt.dayofweek)
        .groupby('day_of_week')['amount']
        .agg(['sum', 'mean', 'count'])
        .reset_index()
    )

// Go 语言错误处理与接口示例
package main

import (
    "errors"
    "fmt"
)

// 自定义错误类型 - AI 理解错误包装模式
type ValidationError struct {
    Field   string
    Message string
}

func (e *ValidationError) Error() string {
    return fmt.Sprintf("%s: %s", e.Field, e.Message)
}

// Reader 接口定义 - AI 会识别实现关系
type Reader interface {
    Read(p []byte) (n int, err error)
}

// 带泛型的数据处理
type Stack[T any] struct {
    items []T
}

func (s *Stack[T]) Push(item T) {
    s.items = append(s.items, item)
}

func (s *Stack[T]) Pop() (T, error) {
    if len(s.items) == 0 {
        var zero T
        return zero, errors.New("stack is empty")
    }
    item := s.items[len(s.items)-1]
    s.items = s.items[:len(s.items)-1]
    return item, nil
}

// 工厂模式示例 - AI 提供构造函数建议
type Database interface {
    Query(sql string) ([]string, error)
}

type postgresDB struct {
    connection string
}

func NewPostgresDB(conn string) (*postgresDB, error) {
    if conn == "" {
        return nil, &ValidationError{
            Field:   "connection",
            Message: "cannot be empty",
        }
    }
    return &postgresDB{connection: conn}, nil
}

// Rust 所有权与生命周期示例
use std::collections::HashMap;

// 结构体定义 - AI 理解生命周期参数
#[derive(Debug)]
struct Config<'a> {
    name: &'a str,
    value: String,
}

// 实现方法带生命周期约束
impl<'a> Config<'a> {
    fn new(name: &'a str, value: &str) -> Self {
        Config {
            name,
            value: value.to_string(),
        }
    }

    fn update(&mut self, value: String) {
        self.value = value;
    }
}

// 泛型 trait 实现
trait Process {
    fn process(&self) -> String;
}

#[derive(Debug)]
struct DataProcessor {
    data: Vec<i32>,
}

impl DataProcessor {
    fn new() -> Self {
        DataProcessor { data: Vec::new() }
    }

    fn add(&mut self, value: i32) {
        self.data.push(value);
    }
}

impl Process for DataProcessor {
    fn process(&self) -> String {
        // AI 会建议使用链式方法而非循环
        let sum: i32 = self.data.iter().sum();
        let count = self.data.len() as i32;
        format!("Average: {}", sum / count)
    }
}

// Result 类型处理 - AI 理解错误传播
fn parse_config(path: &str) -> Result<Config, Box<dyn std::error::Error>> {
    let content = std::fs::read_to_string(path)?;
    // 解析逻辑
    Ok(Config::new("default", &content))
}

// 模式匹配与 Option 处理
fn find_item<'a>(
    cache: &'a HashMap<String, String>,
    key: &str
) -> Option<&'a str> {
    match cache.get(key) {
        Some(value) => Some(value),
        None => None,
    }
}

// Vue 3 组合式 API 示例
import { ref, computed, watch, onMounted } from 'vue'

// 定义 composable - AI 理解其返回结构
function usePagination<T>(items: Ref<T[]>) {
  const currentPage = ref(1)
  const pageSize = ref(10)

  const totalPages = computed(() => 
    Math.ceil(items.value.length / pageSize.value)
  )

  const paginatedItems = computed(() => {
    const start = (currentPage.value - 1) * pageSize.value
    return items.value.slice(start, start + pageSize.value)
  })

  const nextPage = () => {
    if (currentPage.value < totalPages.value) {
      currentPage.value++
    }
  }

  const prevPage = () => {
    if (currentPage.value > 1) {
      currentPage.value--
    }
  }

  // AI 会识别这是标准的分页模式并提供使用建议
  return {
    currentPage: readonly(currentPage),
    pageSize,
    totalPages,
    paginatedItems,
    nextPage,
    prevPage,
  }
}

// 使用 async/await 的 composable
async function useFetch<T>(url: string) {
  const data = ref<T | null>(null)
  const loading = ref(false)
  const error = ref<Error | null>(null)

  async function fetchData() {
    loading.value = true
    try {
      const response = await fetch(url)
      data.value = await response.json()
    } catch (e) {
      error.value = e as Error
    } finally {
      loading.value = false
    }
  }

  onMounted(fetchData)

  return {
    data: readonly(data),
    loading: readonly(loading),
    error: readonly(error),
    refetch: fetchData,
  }
}

# FastAPI 路径操作函数示例
# AI 理解 Pydantic 模型和依赖注入模式

from fastapi import FastAPI, Depends, HTTPException, Query
from pydantic import BaseModel, Field, validator
from typing import Optional
from enum import Enum

app = FastAPI()

# 定义枚举类型
class Category(str, Enum):
    electronics = "electronics"
    clothing = "clothing"
    food = "food"

# Pydantic 模型 - AI 提供字段验证建议
class Product(BaseModel):
    id: Optional[int] = None
    name: str = Field(..., min_length=1, max_length=100)
    price: float = Field(..., gt=0)
    category: Category
    tags: list[str] = []

    @validator('name')
    def name_must_be_valid(cls, v):
        if not v.strip():
            raise ValueError('Name cannot be empty')
        return v.title()

    class Config:
        schema_extra = {
            "example": {
                "name": "Laptop",
                "price": 999.99,
                "category": "electronics",
                "tags": ["computer", "tech"]
            }
        }

# 依赖注入示例
async def get_current_user(token: str = Depends(lambda: "fake-token")):
    """模拟用户认证 - AI 理解依赖模式"""
    return {"user_id": 1, "username": "john"}

# 路径操作函数
@app.get("/products", response_model=list[Product])
async def list_products(
    skip: int = Query(0, ge=0),
    limit: int = Query(10, ge=1, le=100),
    category: Optional[Category] = None,
    current_user: dict = Depends(get_current_user)
):
    """获取产品列表 - AI 提供完整的参数提示"""
    # AI 会建议使用数据库查询而非内存模拟
    products = [
        Product(name="Test", price=10.0, category=Category.electronics)
    ]

    if category:
        products = [p for p in products if p.category == category]

    return products[skip : skip + limit]

@app.post("/products", response_model=Product, status_code=201)
async def create_product(
    product: Product,
    current_user: dict = Depends(get_current_user)
):
    """创建产品 - AI 提供请求体验证提示"""
    return product

