import * as vscode from 'vscode';

/**
 * 团队 AI 配置扩展 - 激活函数
 * 提供团队级别的 AI 开发环境配置管理功能
 */
export function activate(context: vscode.ExtensionContext) {
  console.log('团队 AI 配置扩展已激活！');

  // 注册命令：显示团队 AI 使用指南
  const showGuidelinesCommand = vscode.commands.registerCommand(
    'teamAI.showGuidelines',
    async () => {
      const panel = vscode.window.createWebviewPanel(
        'teamAIGuidelines',
        '团队 AI 使用指南',
        vscode.ViewColumn.One,
        { enableScripts: true }
      );

      panel.webview.html = getGuidelinesHtml();
    }
  );

  // 注册命令：验证团队配置
  const validateConfigCommand = vscode.commands.registerCommand(
    'teamAI.validateConfig',
    async () => {
      const config = vscode.workspace.getConfiguration('teamAI');
      const issues: string[] = [];

      // 验证配置项
      const codeStyle = config.get<string>('codeStyle');
      if (!['standard', 'compact', 'detailed'].includes(codeStyle || '')) {
        issues.push(`无效的 codeStyle 配置: ${codeStyle}`);
      }

      const maxLineLength = config.get<number>('maxLineLength');
      if (maxLineLength !== undefined && (maxLineLength < 80 || maxLineLength > 200)) {
        issues.push(`maxLineLength 超出建议范围 (80-200): ${maxLineLength}`);
      }

      // 显示验证结果
      if (issues.length === 0) {
        vscode.window.showInformationMessage('✅ 团队 AI 配置验证通过！');
      } else {
        vscode.window.showWarningMessage(`⚠️ 发现 ${issues.length} 个配置问题`);
        issues.forEach(issue => console.warn(`[团队 AI] ${issue}`));
      }
    }
  );

  // 注册命令：同步团队设置
  const syncSettingsCommand = vscode.commands.registerCommand(
    'teamAI.syncSettings',
    async () => {
      const confirmation = await vscode.window.showInformationMessage(
        '确定要同步团队设置吗？这将覆盖部分本地设置。',
        '同步',
        '取消'
      );

      if (confirmation === '同步') {
        // 获取工作区配置
        const workspaceConfig = vscode.workspace.getConfiguration('workspace');

        // 应用团队默认值
        const teamDefaults = {
          'editor.tabSize': 2,
          'editor.formatOnSave': true,
          'files.autoSave': 'afterDelay'
        };

        // 更新配置
        for (const [key, value] of Object.entries(teamDefaults)) {
          await workspaceConfig.update(key, value, vscode.ConfigurationTarget.Workspace);
        }

        vscode.window.showInformationMessage('✅ 团队设置同步完成！');
      }
    }
  );

  // 将命令添加到订阅列表
  context.subscriptions.push(
    showGuidelinesCommand,
    validateConfigCommand,
    syncSettingsCommand
  );
}

/**
 * 生成团队 AI 使用指南的 HTML 内容
 */
function getGuidelinesHtml(): string {
  return `
    <!DOCTYPE html>
    <html>
    <head>
      <style>
        body { font-family: -apple-system, sans-serif; padding: 20px; line-height: 1.6; }
        h1 { color: #007acc; border-bottom: 2px solid #007acc; padding-bottom: 10px; }
        h2 { color: #333; margin-top: 30px; }
        code { background: #f4f4f4; padding: 2px 6px; border-radius: 3px; }
        pre { background: #1e1e1e; color: #d4d4d4; padding: 15px; border-radius: 5px; overflow-x: auto; }
        .tip { background: #e7f5ff; border-left: 4px solid #007acc; padding: 10px 15px; margin: 15px 0; }
        .warning { background: #fff3cd; border-left: 4px solid #ffc107; padding: 10px 15px; margin: 15px 0; }
      </style>
    </head>
    <body>
      <h1>🤖 团队 AI 使用指南</h1>

      <div class="tip">
        <strong>💡 快速提示：</strong> 使用 <code>Ctrl+Shift+G</code> 可随时打开本指南
      </div>

      <h2>📋 编码规范</h2>
      <ul>
        <li><strong>变量命名：</strong> 使用 camelCase</li>
        <li><strong>类命名：</strong> 使用 PascalCase</li>
        <li><strong>常量命名：</strong> 使用 UPPER_SNAKE_CASE</li>
        <li><strong>函数命名：</strong> 使用动词前缀（get、set、fetch、create）</li>
      </ul>

      <h2>📝 注释规范</h2>
      <pre>/**
 * 获取用户信息
 * @param userId - 用户唯一标识
 * @returns 用户信息对象
 * @throws {UserNotFoundError} 用户不存在时抛出
 */</pre>

      <h2>⚠️ 注意事项</h2>
      <div class="warning">
        <ul>
          <li>AI 生成的代码必须经过人工审查</li>
          <li>禁止在代码中包含硬编码的密钥或密码</li>
          <li>敏感操作必须添加错误处理</li>
        </ul>
      </div>

      <h2>🔧 快捷命令</h2>
      <ul>
        <li><code>Ctrl+Shift+G</code> - 显示本指南</li>
        <li><code>teamAI.validateConfig</code> - 验证配置</li>
        <li><code>teamAI.syncSettings</code> - 同步团队设置</li>
      </ul>
    </body>
    </html>
  `;
}

// 扩展停用函数
export function deactivate() {
  console.log('团队 AI 配置扩展已停用');
}

