# 示例2：使用向量数据库构建个人知识库（简化版）
# 这是一个概念性示例，展示知识库的核心工作原理

import { v4 as uuidv4 } from 'uuid';

// 知识条目接口
interface KnowledgeItem {
  id: string;
  title: string;
  content: string;
  tags: string[];
  embedding: number[];  // 向量表示
  createdAt: Date;
}

// 简化的向量生成（实际使用 OpenAI/Claude 等 API）
function generateEmbedding(text: string): number[] {
  // 这里应该是实际的 embedding API 调用
  // 简化版本：返回随机向量作为演示
  return Array.from({ length: 1536 }, () => Math.random() - 0.5);
}

// 计算余弦相似度
function cosineSimilarity(a: number[], b: number[]): number {
  const dotProduct = a.reduce((sum, val, i) => sum + val * b[i], 0);
  const magnitudeA = Math.sqrt(a.reduce((sum, val) => sum + val * val, 0));
  const magnitudeB = Math.sqrt(b.reduce((sum, val) => sum + val * val, 0));
  return dotProduct / (magnitudeA * magnitudeB);
}

class SimpleKnowledgeBase {
  private items: KnowledgeItem[] = [];

  // 添加知识条目
  addItem(title: string, content: string, tags: string[]): void {
    const item: KnowledgeItem = {
      id: uuidv4(),
      title,
      content,
      tags,
      embedding: generateEmbedding(title + ' ' + content),
      createdAt: new Date()
    };
    this.items.push(item);
    console.log(`✅ 知识条目已添加: ${title}`);
  }

  // 语义搜索
  search(query: string, topK: number = 3): KnowledgeItem[] {
    const queryEmbedding = generateEmbedding(query);

    // 计算相似度并排序
    const results = this.items.map(item => ({
      item,
      similarity: cosineSimilarity(queryEmbedding, item.embedding)
    }));

    return results
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, topK)
      .map(r => r.item);
  }
}

// 使用示例
const kb = new SimpleKnowledgeBase();

// 添加学习笔记
kb.addItem(
  'TypeScript 泛型约束',
  '使用 extends 关键字可以约束泛型的类型范围，例如：<T extends { id: number }> 表示 T 必须包含 id 属性',
