);

kb.addItem(
  'Git 撤销操作',
  'git reset --soft HEAD~1 可以撤销最后一次提交，保留更改；git checkout -- file 可以丢弃工作区的更改',
  ['git', 'version-control']
);

// 语义搜索
console.log('\n🔍 搜索"类型系统限制"');
const results = kb.search('类型系统限制');
results.forEach(r => console.log(`- ${r.title}: ${r.content.substring(0, 50)}...`));

